import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Settings } from 'lucide-react';

export default function SettingsPage() {
  const navigate = useNavigate();
  const [settings, setSettings] = useState({
    notifications: true,
    newsletter: false,
    privacy: 'public',
  });

  return (
    <div className="min-h-screen bg-gray-50 p-4">
      <button onClick={() => navigate('/dashboard')} className="flex items-center gap-2 text-blue-600 mb-8">
        <ArrowLeft className="w-5 h-5" /> Back
      </button>
      <div className="max-w-2xl mx-auto bg-white rounded-lg shadow p-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-8 flex items-center gap-2">
          <Settings className="w-8 h-8" /> Settings
        </h1>

        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <label className="text-gray-900 font-semibold">Email Notifications</label>
            <input
              type="checkbox"
              checked={settings.notifications}
              onChange={(e) => setSettings({...settings, notifications: e.target.checked})}
              className="w-5 h-5"
            />
          </div>
          
          <div className="flex items-center justify-between">
            <label className="text-gray-900 font-semibold">Subscribe to Newsletter</label>
            <input
              type="checkbox"
              checked={settings.newsletter}
              onChange={(e) => setSettings({...settings, newsletter: e.target.checked})}
              className="w-5 h-5"
            />
          </div>

          <button className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition">
            Save Settings
          </button>
        </div>
      </div>
    </div>
  );
}
